export function getProvinceByCode(provinceCode) {
  const code = String(provinceCode || "").trim();

  return VIETNAM_ADMINISTRATIVE_2025.find(
    (province) => String(province.code) === code
  ) || null;
}

export function getWardsByProvince(provinceCode) {
  const province = getProvinceByCode(provinceCode);

  return province?.wards || [];
}

export function getProvinceCoordinates(provinceCode) {
  const province = getProvinceByCode(provinceCode);

  const coordinatesByName = {
    "Thành phố Hà Nội": { lat: 21.0285, lng: 105.8542 },
    "Thành phố Hải Phòng": { lat: 20.8449, lng: 106.6881 },
    "Thành phố Đà Nẵng": { lat: 16.0544, lng: 108.2022 },
    "Thành phố Hồ Chí Minh": { lat: 10.8231, lng: 106.6297 },
    "Thành phố Cần Thơ": { lat: 10.0452, lng: 105.7469 },
    "Thành phố Huế": { lat: 16.4637, lng: 107.5909 }
  };

  return coordinatesByName[province?.name] || { lat: 16.0, lng: 105.5 };
}